// // This module implements a 16-bit DRAM cell with a 16-bit data input, a 16-bit data output, a write enable signal, and a clock signal. When the write enable signal is low, the data input should be written to the cell on the rising edge of the clock. When the write enable signal is high, the data output should provide the stored value of the cell on the next clock edge.
module dram_cell (  
    input clk,  
    input write_enable,  
    input [15:0] data_in,  
    output reg [15:0] data_out  
);  
    reg [15:0] storage;  

    always @(posedge clk) begin  
        if (write_enable) begin  
            storage <= data_in;  
        end  
        data_out <= storage;  
    end  
endmodule
